export interface Product {
  id: string;
  name: string;
  description: string;
  price: number;
  image: string;
  rating: number;
  category: CategoryID;
}

export type CategoryID = 'sun' | 'all-skin' | 'grasse' | 'hair' | 'anti-aging' | 'body' | 'sensitive';

export interface Category {
  id: CategoryID;
  title: string;
  subtitle: string;
  description: string;
  color: string;
  bgLight: string;
  bgDark: string;
  icon: string;
}

export interface CartItem extends Product {
  quantity: number;
}

import { GoogleGenAI, Type } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const getAIProductInsight = async (productName: string, category: string) => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `بصفتك خبير تجميل طبي، قدم وصفاً قصيراً وجذاباً جداً لمنتج اسمه "${productName}" في قسم "${category}". ركز على الفوائد الطبية والجمالية.`,
      config: {
        maxOutputTokens: 150,
      }
    });
    return response.text;
  } catch (error) {
    console.error("AI Insight Error:", error);
    return null;
  }
};

