import React, { useState, useEffect, useRef } from 'react';
import { Navbar } from './components/Navbar';
import { CategoryHero } from './components/CategoryHero';
import { ProductCard } from './components/ProductCard';
import { CartSidebar } from './components/CartSidebar';
import { CATEGORIES, MOCK_PRODUCTS } from './constants';
import { Product, CartItem, CategoryID } from './types';
import { AppIcon } from './components/Icons';

function App() {
  const [cart, setCart] = useState<CartItem[]>([]);
  const [isCartOpen, setIsCartOpen] = useState(false);
  const [activeCategoryIndex, setActiveCategoryIndex] = useState(0);
  const sectionRefs = useRef<(HTMLDivElement | null)[]>([]);

  useEffect(() => {
    const handleScroll = () => {
      const scrollPos = window.scrollY + window.innerHeight / 2;
      sectionRefs.current.forEach((ref, index) => {
        if (ref && scrollPos >= ref.offsetTop && scrollPos < ref.offsetTop + ref.offsetHeight) {
          setActiveCategoryIndex(index);
        }
      });
    };

    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const addToCart = (product: Product) => {
    setCart(prev => {
      const existing = prev.find(item => item.id === product.id);
      if (existing) {
        return prev.map(item => 
          item.id === product.id ? { ...item, quantity: item.quantity + 1 } : item
        );
      }
      return [...prev, { ...product, quantity: 1 }];
    });
    setIsCartOpen(true);
  };

  const updateQuantity = (id: string, delta: number) => {
    setCart(prev => prev.map(item => 
      item.id === id ? { ...item, quantity: Math.max(1, item.quantity + delta) } : item
    ));
  };

  const removeFromCart = (id: string) => {
    setCart(prev => prev.filter(item => item.id !== id));
  };

  const totalCartItems = cart.reduce((sum, item) => sum + item.quantity, 0);

  return (
    <div className="min-h-screen bg-white">
      <Navbar onOpenCart={() => setIsCartOpen(true)} cartCount={totalCartItems} />

      {/* Dynamic Indicators for Categories */}
      <div className="fixed left-6 top-1/2 -translate-y-1/2 z-40 hidden lg:flex flex-col gap-4">
        {CATEGORIES.map((cat, idx) => (
          <button
            key={cat.id}
            onClick={() => sectionRefs.current[idx]?.scrollIntoView({ behavior: 'smooth' })}
            className={`w-3 h-3 rounded-full transition-all duration-300 ${
              activeCategoryIndex === idx 
                ? `${cat.bgDark} scale-150` 
                : 'bg-gray-300 hover:bg-gray-400'
            }`}
            title={cat.title}
          />
        ))}
      </div>

      <main>
        {/* Intro Section */}
        <section className="h-[90vh] flex items-center justify-center text-center px-4 relative overflow-hidden bg-slate-900">
          <div className="absolute inset-0 opacity-40">
            <img src="https://images.unsplash.com/photo-1550584552-466522757bc1?auto=format&fit=crop&q=80&w=2000" className="w-full h-full object-cover" />
          </div>
          <div className="absolute inset-0 bg-gradient-to-t from-slate-900 via-slate-900/40 to-transparent"></div>

          <div className="relative z-10 max-w-4xl space-y-8 animate-in fade-in slide-in-from-bottom-8 duration-1000">
            <div className="inline-block bg-indigo-600/20 backdrop-blur-md border border-indigo-400/30 px-6 py-2 rounded-full text-indigo-400 font-bold text-sm tracking-widest uppercase">
              الجيل القادم من العناية الطبية
            </div>
            <h1 className="text-5xl md:text-8xl font-black text-white leading-tight">
              احترافية <span className="text-indigo-400">تلامس</span> خيالك
            </h1>
            <p className="text-xl text-gray-300 max-w-2xl mx-auto font-medium">
              نحن لا نبيع المنتجات فحسب، بل نصمم لك تجربة متكاملة للعناية بالبشرة مبنية على أبحاث علمية دقيقة وجماليات عالمية.
            </p>
            <div className="pt-8">
              <button 
                onClick={() => sectionRefs.current[0]?.scrollIntoView({ behavior: 'smooth' })}
                className="bg-white text-slate-900 px-10 py-5 rounded-[2rem] font-black text-xl hover:scale-105 transition-all shadow-2xl shadow-white/10"
              >
                ابدأ جولتك الآن
              </button>
            </div>
          </div>
        </section>

        {/* Dynamic Thematic Sections */}
        <div id="sections">
          {CATEGORIES.map((category, index) => (
            <div 
              key={category.id} 
              ref={el => sectionRefs.current[index] = el}
              className="scroll-mt-20"
            >
              <CategoryHero 
                category={category} 
                isActive={activeCategoryIndex === index} 
              />

              <div className={`py-20 ${category.bgLight}/30 border-t border-white/50`}>
                <div className="max-w-7xl mx-auto px-4">
                  <div className="flex items-center justify-between mb-12">
                    <div>
                      <h2 className="text-3xl font-black text-gray-900">أبرز منتجات {category.title}</h2>
                      <p className="text-gray-500 mt-2">مختارة بعناية لأفضل النتائج الطبية</p>
                    </div>
                    <button className={`flex items-center gap-2 font-bold ${category.color} hover:gap-4 transition-all`}>
                      عرض الكل
                      <AppIcon name="ArrowLeft" size={20} />
                    </button>
                  </div>

                  <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-8">
                    {MOCK_PRODUCTS
                      .filter(p => p.category === category.id)
                      .concat(MOCK_PRODUCTS.filter(p => p.category === category.id)) // Repeat mock data to fill grid
                      .slice(0, 4)
                      .map((product, pIdx) => (
                        <ProductCard 
                          key={`${product.id}-${pIdx}`} 
                          product={product} 
                          color={category.color}
                          onAddToCart={addToCart}
                        />
                      ))
                    }
                  </div>
                </div>
              </div>
            </div>
          ))}
        </div>

        {/* Footer */}
        <footer id="about" className="bg-slate-900 text-white py-20 px-4">
          <div className="max-w-7xl mx-auto grid grid-cols-1 md:grid-cols-4 gap-12">
            <div className="space-y-6">
              <div className="flex items-center gap-2">
                <div className="bg-indigo-600 p-2 rounded-lg text-white">
                  <AppIcon name="ShieldCheck" size={24} />
                </div>
                <span className="text-2xl font-bold tracking-tight">DermoCare<span className="text-indigo-400">Pro</span></span>
              </div>
              <p className="text-slate-400 leading-relaxed">
                متجر طبي متكامل يجمع بين أرقى الماركات العالمية والخبرة الطبية لتقديم حلول حقيقية لكل مشاكل البشرة والشعر.
              </p>
            </div>

            <div>
              <h4 className="text-lg font-bold mb-6">روابط سريعة</h4>
              <ul className="space-y-4 text-slate-400">
                <li><a href="#" className="hover:text-white transition-colors">الأقسام الطبية</a></li>
                <li><a href="#" className="hover:text-white transition-colors">سياسة الخصوصية</a></li>
                <li><a href="#" className="hover:text-white transition-colors">الشحن والتوصيل</a></li>
                <li><a href="#" className="hover:text-white transition-colors">الأسئلة الشائعة</a></li>
              </ul>
            </div>

            <div>
              <h4 className="text-lg font-bold mb-6">تواصل معنا</h4>
              <ul className="space-y-4 text-slate-400">
                <li className="flex items-center gap-3"><AppIcon name="Activity" size={18} /> الرياض، المملكة العربية السعودية</li>
                <li className="flex items-center gap-3"><AppIcon name="Wind" size={18} /> contact@dermocare.pro</li>
                <li className="flex items-center gap-3"><AppIcon name="ShieldCheck" size={18} /> +966 500 000 000</li>
              </ul>
            </div>

            <div>
              <h4 className="text-lg font-bold mb-6">النشرة الإخبارية</h4>
              <p className="text-slate-400 mb-4 text-sm">اشترك للحصول على آخر العروض والنصائح الطبية.</p>
              <div className="flex gap-2">
                <input 
                  type="email" 
                  placeholder="بريدك الإلكتروني" 
                  className="bg-slate-800 border border-slate-700 rounded-xl px-4 py-2 flex-grow focus:outline-none focus:border-indigo-500"
                />
                <button className="bg-indigo-600 text-white px-4 py-2 rounded-xl font-bold">اشترك</button>
              </div>
            </div>
          </div>
          <div className="max-w-7xl mx-auto mt-20 pt-8 border-t border-slate-800 text-center text-slate-500 text-sm">
            © 2024 DermoCare Pro. جميع الحقوق محفوظة.
          </div>
        </footer>
      </main>

      <CartSidebar 
        isOpen={isCartOpen} 
        onClose={() => setIsCartOpen(false)} 
        items={cart}
        onUpdateQuantity={updateQuantity}
        onRemove={removeFromCart}
      />
    </div>
  );
}

export default App;

import React from 'react';
