                      .map((product) => (
                        <ProductCard 
                          key={product.id} 
                          product={product} 
                          color={category.color}
                          onAddToCart={addToCart}
                          onQuickView={setSelectedProduct}
                        />
                      ))
                    }
                  </div>
                </div>
              </div>
            </div>
          ))}
        </div>

        {/* ... (Footer remains same) ... */}
        <footer className="bg-slate-950 text-white py-24 px-6 border-t border-white/5">
           <div className="max-w-7xl mx-auto text-center space-y-8">
              <div className="flex justify-center items-center gap-3">
                <AppIcon name="ShieldCheck" size={40} className="text-indigo-500" />
                <span className="text-4xl font-black">DermoCare Pro</span>
              </div>
              <p className="text-slate-400 max-w-xl mx-auto">نحن نغير مفهوم العناية بالبشرة من مجرد رفاهية إلى ضرورة طبية مدروسة.</p>
              <div className="pt-8 text-slate-600 text-sm">© 2024 DermoCare Pro Global. Clinical-Luxury Experience.</div>
           </div>
        </footer>
      </main>

      <CartSidebar 
        isOpen={isCartOpen} 
        onClose={() => setIsCartOpen(false)} 
        items={cart}
        onUpdateQuantity={updateQuantity}
        onRemove={removeFromCart}
      />

      <ProductModal 
        product={selectedProduct} 
        onClose={() => setSelectedProduct(null)} 
        onAddToCart={addToCart}
        color={CATEGORIES.find(c => c.id === selectedProduct?.category)?.color || 'text-indigo-600'}
      />

      <AIConsultant />
    </div>
  );
}

