import React, { useState, useEffect, useRef } from 'react';
import { Navbar } from './components/Navbar';
import { CategoryHero } from './components/CategoryHero';
import { ProductCard } from './components/ProductCard';
import { CartSidebar } from './components/CartSidebar';
import { AIConsultant } from './components/AIConsultant';
import { ProductModal } from './components/ProductModal';
import { CATEGORIES, MOCK_PRODUCTS } from './constants';
import { Product, CartItem } from './types';
import { AppIcon } from './components/Icons';

function App() {
  const [cart, setCart] = useState<CartItem[]>([]);
  const [isCartOpen, setIsCartOpen] = useState(false);
  const [activeCategoryIndex, setActiveCategoryIndex] = useState(0);
  const [selectedProduct, setSelectedProduct] = useState<Product | null>(null);
  const sectionRefs = useRef<(HTMLDivElement | null)[]>([]);

  useEffect(() => {
    const handleScroll = () => {
      const scrollPos = window.scrollY + window.innerHeight / 2;
      sectionRefs.current.forEach((ref, index) => {
        if (ref && scrollPos >= ref.offsetTop && scrollPos < ref.offsetTop + ref.offsetHeight) {
          setActiveCategoryIndex(index);
        }
      });
    };

    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const addToCart = (product: Product) => {
    setCart(prev => {
      const existing = prev.find(item => item.id === product.id);
      if (existing) {
        return prev.map(item => 
          item.id === product.id ? { ...item, quantity: item.quantity + 1 } : item
        );
      }
      return [...prev, { ...product, quantity: 1 }];
    });
    if (window.navigator.vibrate) window.navigator.vibrate(50);
    setIsCartOpen(true);
    setSelectedProduct(null);
  };

  const updateQuantity = (id: string, delta: number) => {
    setCart(prev => prev.map(item => 
      item.id === id ? { ...item, quantity: Math.max(1, item.quantity + delta) } : item
    ));
  };

  const removeFromCart = (id: string) => {
    setCart(prev => prev.filter(item => item.id !== id));
  };

  const totalCartItems = cart.reduce((sum, item) => sum + item.quantity, 0);

  return (
    <div className="min-h-screen bg-slate-50 selection:bg-indigo-100 selection:text-indigo-900">
      <Navbar onOpenCart={() => setIsCartOpen(true)} cartCount={totalCartItems} />

      <div className="fixed left-6 top-1/2 -translate-y-1/2 z-40 hidden lg:flex flex-col gap-4">
        {CATEGORIES.map((cat, idx) => (
          <button
            key={cat.id}
            onClick={() => sectionRefs.current[idx]?.scrollIntoView({ behavior: 'smooth' })}
            className={`group relative flex items-center`}
          >
            <span className={`absolute right-6 opacity-0 group-hover:opacity-100 transition-all bg-white px-3 py-1 rounded-lg text-xs font-bold shadow-sm whitespace-nowrap border border-gray-100`}>
              {cat.title}
            </span>
            <div className={`w-3 h-3 rounded-full border-2 transition-all duration-300 ${
              activeCategoryIndex === idx 
                ? `${cat.bgDark} scale-150 border-white ring-2 ring-indigo-100` 
                : 'bg-gray-300 border-transparent hover:bg-gray-400'
            }`} />
          </button>
        ))}
      </div>

      <main>
        <section className="h-screen flex items-center justify-center text-center px-4 relative overflow-hidden bg-slate-950">
          <div className="absolute inset-0">
             <div className="absolute top-0 left-0 w-full h-full bg-[radial-gradient(circle_at_center,_var(--tw-gradient-stops))] from-indigo-500/20 via-transparent to-transparent"></div>
             <img src="https://images.unsplash.com/photo-1612349317150-e413f6a5b16d?auto=format&fit=crop&q=80&w=2000" className="w-full h-full object-cover opacity-30 grayscale" />
          </div>

          <div className="relative z-10 max-w-5xl space-y-12 px-6">
            <div className="inline-flex items-center gap-2 bg-indigo-500/10 backdrop-blur-xl border border-indigo-400/20 px-6 py-3 rounded-full text-indigo-300 font-bold text-sm tracking-[0.2em] uppercase animate-in fade-in zoom-in duration-700">
              <AppIcon name="ShieldCheck" size={16} />
              خبراء العناية الطبية في الجزائر
            </div>

            <h1 className="text-6xl md:text-9xl font-black text-white leading-[1.1] tracking-tighter text-balance">
              نبتكر <br/>
              <span className="bg-clip-text text-transparent bg-gradient-to-r from-indigo-400 via-purple-400 to-pink-400">جمالك الطبي</span>
            </h1>

            <p className="text-xl md:text-2xl text-slate-400 max-w-2xl mx-auto font-light leading-relaxed">
              أفضل الماركات العالمية المختارة بعناية لتناسب بشرتك، متوفرة الآن مع خدمة التوصيل السريع لـ 58 ولاية.
            </p>

            <div className="flex flex-col md:flex-row gap-6 justify-center pt-8">
              <button 
                onClick={() => sectionRefs.current[0]?.scrollIntoView({ behavior: 'smooth' })}
                className="group relative bg-white text-slate-950 px-12 py-6 rounded-full font-black text-xl overflow-hidden transition-all hover:scale-105 active:scale-95"
              >
                <span className="relative z-10">اكتشف مختبراتنا</span>
                <div className="absolute inset-0 bg-gradient-to-r from-indigo-100 to-white transform scale-x-0 group-hover:scale-x-100 transition-transform origin-left"></div>
              </button>
            </div>
          </div>
        </section>

        <div id="sections">
          {CATEGORIES.map((category, index) => (
            <div 
              key={category.id} 
              ref={el => sectionRefs.current[index] = el}
              className="scroll-mt-20 overflow-hidden"
            >
              <CategoryHero 
                category={category} 
                isActive={activeCategoryIndex === index} 
              />

              <div className={`py-32 ${category.bgLight}/40 relative`}>
                <div className="max-w-7xl mx-auto px-6">
                  <div className="flex flex-col md:flex-row items-end justify-between mb-16 gap-6">
                    <div className="space-y-2">
                      <div className={`h-1 w-20 ${category.bgDark} rounded-full`}></div>
                      <h2 className="text-4xl md:text-5xl font-black text-slate-900">{category.title}</h2>
                      <p className="text-slate-500 text-lg">المنتجات الأكثر مبيعاً في هذا القسم</p>
                    </div>
                  </div>

                  <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-10">
                    {MOCK_PRODUCTS
                      .filter(p => p.category === category.id)
                      .map((product) => (
                        <ProductCard 
                          key={product.id} 
                          product={product} 
                          color={category.color}
                          onAddToCart={addToCart}
                          onQuickView={setSelectedProduct}
                        />
                      ))
                    }
                  </div>
                </div>
              </div>
            </div>
          ))}
        </div>

        <footer className="bg-slate-950 text-white py-24 px-6 border-t border-white/5">
           <div className="max-w-7xl mx-auto text-center space-y-12">
              <div className="flex justify-center items-center gap-3">
                <AppIcon name="ShieldCheck" size={40} className="text-indigo-500" />
                <span className="text-4xl font-black">Lumière Derme الجزائر</span>
              </div>
              <p className="text-slate-400 max-w-xl mx-auto">نحن نغير مفهوم العناية بالبشرة في الجزائر من خلال توفير المنتجات الأصلية والنصائح الطبية الموثوقة.</p>
              <div className="flex justify-center gap-8 text-slate-400 font-bold">
                 <span>توصيل لـ 58 ولاية</span>
                 <span>دفع عند الاستلام</span>
                 <span>منتجات أصلية 100%</span>
              </div>
              <div className="pt-8 text-slate-600 text-sm border-t border-white/5">© 2024 Lumière Derme Global. Clinical-Luxury Experience in Algeria.</div>
           </div>
        </footer>
      </main>

      <CartSidebar 
        isOpen={isCartOpen} 
        onClose={() => setIsCartOpen(false)} 
        items={cart}
        onUpdateQuantity={updateQuantity}
        onRemove={removeFromCart}
      />

      <ProductModal 
        product={selectedProduct} 
        onClose={() => setSelectedProduct(null)} 
        onAddToCart={addToCart}
        color={CATEGORIES.find(c => c.id === selectedProduct?.category)?.color || 'text-indigo-600'}
      />

      <AIConsultant />
    </div>
  );
}

export default App;

import React, { useState, useRef, useEffect } from 'react';
import { GoogleGenAI } from "@google/genai";
import { AppIcon } from './Icons';

export const AIConsultant: React.FC = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [messages, setMessages] = useState<{role: 'user' | 'model', text: string}[]>([
    {role: 'model', text: 'مرحباً بك في Lumière Derme! أنا مستشارك الطبي الذكي، كيف يمكنني مساعدتك في اختيار الروتين المناسب لبشرتك اليوم؟'}
  ]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
  }, [messages]);

  const handleSend = async () => {
    if (!input.trim()) return;
    const userMsg = input;
    setInput('');
    setMessages(prev => [...prev, {role: 'user', text: userMsg}]);
    setIsTyping(true);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const chat = ai.chats.create({
        model: 'gemini-3-flash-preview',
        config: {
          systemInstruction: 'أنت خبير تجميل طبي في متجر Lumière Derme. وظيفتك تقديم نصائح طبية احترافية ومختصرة باللغة العربية. شجع المستخدم على العناية ببشرته واقترح أنواع المنتجات المتاحة في المتجر (واقي شمس، مرطبات، سيرومات).'
        }
      });
      const response = await chat.sendMessage({ message: userMsg });
      setMessages(prev => [...prev, {role: 'model', text: response.text || 'عذراً، واجهت مشكلة في الاتصال.'}]);
    } catch (error) {
      setMessages(prev => [...prev, {role: 'model', text: 'نعتذر، المستشار مشغول حالياً. حاول مجدداً لاحقاً.'}]);
    } finally {
      setIsTyping(false);
    }
  };

  return (
    <div className="fixed bottom-6 right-6 z-[200]">
      {isOpen ? (
        <div className="bg-white w-[350px] h-[500px] rounded-3xl shadow-2xl flex flex-col overflow-hidden border border-gray-100 animate-in slide-in-from-bottom-10 duration-300">
          <div className="bg-indigo-600 p-4 text-white flex justify-between items-center">
            <div className="flex items-center gap-2">
              <div className="bg-white/20 p-2 rounded-lg"><AppIcon name="ShieldCheck" size={18} /></div>
              <span className="font-bold">مستشار البشرة الذكي</span>
            </div>
            <button onClick={() => setIsOpen(false)}><AppIcon name="X" size={20} /></button>
          </div>

          <div ref={scrollRef} className="flex-grow p-4 overflow-y-auto custom-scrollbar space-y-4 bg-gray-50">
            {messages.map((m, i) => (
              <div key={i} className={`flex ${m.role === 'user' ? 'justify-start' : 'justify-end'}`}>
                <div className={`max-w-[80%] p-3 rounded-2xl text-sm ${
                  m.role === 'user' ? 'bg-indigo-600 text-white rounded-tr-none' : 'bg-white text-gray-800 shadow-sm rounded-tl-none border border-gray-100'
                }`}>
                  {m.text}
                </div>
              </div>
            ))}
            {isTyping && <div className="text-xs text-gray-400 animate-pulse">المستشار يكتب الآن...</div>}
          </div>

          <div className="p-4 bg-white border-t border-gray-100 flex gap-2">
            <input 
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyDown={(e) => e.key === 'Enter' && handleSend()}
              placeholder="اسأل المستشار الطبي..."
              className="flex-grow bg-gray-100 border-none rounded-xl px-4 py-2 text-sm focus:ring-2 focus:ring-indigo-500 outline-none"
            />
            <button onClick={handleSend} className="bg-indigo-600 text-white p-2 rounded-xl">
              <AppIcon name="ArrowLeft" size={18} />
            </button>
          </div>
        </div>
      ) : (
        <button 
          onClick={() => setIsOpen(true)}
          className="bg-indigo-600 text-white p-4 rounded-full shadow-2xl hover:scale-110 transition-transform animate-float flex items-center gap-2 pr-6"
        >
          <AppIcon name="Sparkles" />
          <span className="font-bold text-sm">استشارة طبية مجانية</span>
        </button>
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Product } from '../types';
import { AppIcon } from './Icons';
import { getAIProductInsight } from '../services/geminiService';

interface ProductModalProps {
  product: Product | null;
  onClose: () => void;
  onAddToCart: (p: Product) => void;
  color: string;
}

export const ProductModal: React.FC<ProductModalProps> = ({ product, onClose, onAddToCart, color }) => {
  const [aiInsight, setAiInsight] = useState<string | null>(null);
  const [isLoadingInsight, setIsLoadingInsight] = useState(false);

  useEffect(() => {
    if (product) {
      setAiInsight(null);
      setIsLoadingInsight(true);
      getAIProductInsight(product.name, product.category).then(insight => {
        setAiInsight(insight);
        setIsLoadingInsight(false);
      });
    }
  }, [product]);

  if (!product) return null;

  return (
    <div className="fixed inset-0 z-[300] flex items-center justify-center p-4">
      <div className="absolute inset-0 bg-slate-900/60 backdrop-blur-md" onClick={onClose}></div>
      <div className="relative bg-white w-full max-w-4xl rounded-[2.5rem] overflow-hidden shadow-2xl flex flex-col md:flex-row animate-in fade-in zoom-in duration-300">
        <button onClick={onClose} className="absolute top-6 right-6 z-10 p-2 bg-white/80 backdrop-blur rounded-full hover:bg-white shadow-sm transition-all">
          <AppIcon name="X" size={24} />
        </button>

        <div className="md:w-1/2 h-[300px] md:h-auto relative bg-gray-50">
          <img src={product.image} alt={product.name} className="w-full h-full object-cover" />
        </div>

        <div className="md:w-1/2 p-8 md:p-12 flex flex-col">
          <div className="flex items-center gap-2 mb-4">
            <span className={`px-4 py-1 rounded-full text-xs font-bold bg-gray-100 ${color}`}>تحليل خبير الجمال</span>
          </div>

          <h2 className="text-3xl font-black text-gray-900 mb-2">{product.name}</h2>
          <p className="text-gray-500 mb-8">{product.description}</p>

          <div className="bg-slate-50 rounded-3xl p-6 mb-8 border border-slate-100 relative overflow-hidden">
             <div className="flex items-center gap-2 mb-3 text-indigo-600 font-bold text-sm">
                <AppIcon name="Sparkles" size={16} />
                رأي خبير Lumière Derme الذكي
             </div>
             {isLoadingInsight ? (
               <div className="space-y-2 animate-pulse">
                  <div className="h-3 bg-slate-200 rounded w-full"></div>
                  <div className="h-3 bg-slate-200 rounded w-4/5"></div>
               </div>
             ) : (
               <p className="text-slate-600 text-sm leading-relaxed italic">
                 "{aiInsight || 'جاري تحليل المكونات والفوائد الطبية...'}"
               </p>
             )}
          </div>

          <div className="mt-auto flex items-center justify-between gap-6">
            <div>
              <span className="text-xs text-gray-400 block mb-1">السعر</span>
              <span className="text-4xl font-black text-gray-900">{product.price.toLocaleString()} <small className="text-sm font-normal">دج</small></span>
            </div>
            <button 
              onClick={() => onAddToCart(product)}
              className="flex-grow bg-indigo-600 text-white py-5 rounded-2xl font-bold text-lg shadow-xl shadow-indigo-600/20 hover:bg-indigo-700 transition-all flex items-center justify-center gap-3"
            >
              <AppIcon name="ShoppingBag" size={22} />
              إضافة للسلة
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

