import React, { useState, useEffect, useRef } from 'react';
import { Navbar } from './components/Navbar';
import { CategoryHero } from './components/CategoryHero';
import { ProductCard } from './components/ProductCard';
import { CartSidebar } from './components/CartSidebar';
import { AIConsultant } from './components/AIConsultant';
import { ProductModal } from './components/ProductModal';
import { BrandMarquee } from './components/BrandMarquee';
import { CATEGORIES, MOCK_PRODUCTS } from './constants';
import { Product, CartItem } from './types';
import { AppIcon } from './components/Icons';

function App() {
  const [cart, setCart] = useState<CartItem[]>([]);
  const [isCartOpen, setIsCartOpen] = useState(false);
  const [activeCategoryIndex, setActiveCategoryIndex] = useState(0);
  const [selectedProduct, setSelectedProduct] = useState<Product | null>(null);
  const [searchQuery, setSearchQuery] = useState('');
  const sectionRefs = useRef<(HTMLDivElement | null)[]>([]);

  useEffect(() => {
    const handleScroll = () => {
      const scrollPos = window.scrollY + window.innerHeight / 2;
      sectionRefs.current.forEach((ref, index) => {
        if (ref && scrollPos >= ref.offsetTop && scrollPos < ref.offsetTop + ref.offsetHeight) {
          setActiveCategoryIndex(index);
        }
      });
    };

    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const addToCart = (product: Product) => {
    setCart(prev => {
      const existing = prev.find(item => item.id === product.id);
      if (existing) {
        return prev.map(item => 
          item.id === product.id ? { ...item, quantity: item.quantity + 1 } : item
        );
      }
      return [...prev, { ...product, quantity: 1 }];
    });
    if (window.navigator.vibrate) window.navigator.vibrate(50);
    setIsCartOpen(true);
    setSelectedProduct(null);
  };

  const updateQuantity = (id: string, delta: number) => {
    setCart(prev => prev.map(item => 
      item.id === id ? { ...item, quantity: Math.max(1, item.quantity + delta) } : item
    ));
  };

  const removeFromCart = (id: string) => {
    setCart(prev => prev.filter(item => item.id !== id));
  };

  const filteredProducts = MOCK_PRODUCTS.filter(p => 
    p.name.toLowerCase().includes(searchQuery.toLowerCase()) || 
    p.description.toLowerCase().includes(searchQuery.toLowerCase())
  );

  const totalCartItems = cart.reduce((sum, item) => sum + item.quantity, 0);

  return (
    <div className="min-h-screen bg-slate-50 selection:bg-indigo-100 selection:text-indigo-900">
      <Navbar onOpenCart={() => setIsCartOpen(true)} cartCount={totalCartItems} onSearch={setSearchQuery} />

      <div className="fixed left-6 top-1/2 -translate-y-1/2 z-40 hidden lg:flex flex-col gap-4">
        {CATEGORIES.map((cat, idx) => (
          <button
            key={cat.id}
            onClick={() => sectionRefs.current[idx]?.scrollIntoView({ behavior: 'smooth' })}
            className={`group relative flex items-center`}
          >
            <span className={`absolute right-6 opacity-0 group-hover:opacity-100 transition-all bg-white px-3 py-1 rounded-lg text-xs font-bold shadow-sm whitespace-nowrap border border-gray-100`}>
              {cat.title}
            </span>
            <div className={`w-3 h-3 rounded-full border-2 transition-all duration-300 ${
              activeCategoryIndex === idx 
                ? `${cat.bgDark} scale-150 border-white ring-2 ring-indigo-100` 
                : 'bg-gray-300 border-transparent hover:bg-gray-400'
            }`} />
          </button>
        ))}
      </div>

      <main>
        {/* Hero Section */}
        <section className="h-screen flex items-center justify-center text-center px-4 relative overflow-hidden bg-slate-950">
          <div className="absolute inset-0">
             <div className="absolute top-0 left-0 w-full h-full bg-[radial-gradient(circle_at_center,_var(--tw-gradient-stops))] from-indigo-500/20 via-transparent to-transparent"></div>
             <img src="https://images.unsplash.com/photo-1612349317150-e413f6a5b16d?auto=format&fit=crop&q=80&w=2000" className="w-full h-full object-cover opacity-30 grayscale" />
          </div>

          <div className="relative z-10 max-w-5xl space-y-12 px-6">
            <div className="inline-flex items-center gap-2 bg-indigo-500/10 backdrop-blur-xl border border-indigo-400/20 px-6 py-3 rounded-full text-indigo-300 font-bold text-sm tracking-[0.2em] uppercase animate-in fade-in zoom-in duration-700">
              <AppIcon name="ShieldCheck" size={16} />
              خبراء العناية الطبية في الجزائر
            </div>

            <h1 className="text-6xl md:text-9xl font-black text-white leading-[1.1] tracking-tighter text-balance">
              نبتكر <br/>
              <span className="bg-clip-text text-transparent bg-gradient-to-r from-indigo-400 via-purple-400 to-pink-400">جمالك الطبي</span>
            </h1>

            <p className="text-xl md:text-2xl text-slate-400 max-w-2xl mx-auto font-light leading-relaxed">
              أفضل الماركات العالمية المختارة بعناية لتناسب بشرتك، متوفرة الآن مع خدمة التوصيل السريع لـ 58 ولاية.
            </p>

            <div className="flex flex-col md:flex-row gap-6 justify-center pt-8">
              <button 
                onClick={() => sectionRefs.current[0]?.scrollIntoView({ behavior: 'smooth' })}
                className="group relative bg-white text-slate-950 px-12 py-6 rounded-full font-black text-xl overflow-hidden transition-all hover:scale-105 active:scale-95"
              >
                <span className="relative z-10">اكتشف مختبراتنا</span>
                <div className="absolute inset-0 bg-gradient-to-r from-indigo-100 to-white transform scale-x-0 group-hover:scale-x-100 transition-transform origin-left"></div>
              </button>
            </div>
          </div>
        </section>

        <BrandMarquee />

        {/* Search Results / Categories */}
        {searchQuery ? (
          <section className="py-32 bg-slate-50 min-h-screen">
             <div className="max-w-7xl mx-auto px-6">
                <div className="mb-12">
                   <h2 className="text-3xl font-black text-slate-900">نتائج البحث عن: "{searchQuery}"</h2>
                   <p className="text-slate-500">تم العثور على {filteredProducts.length} منتجات</p>
                </div>
                {filteredProducts.length > 0 ? (
                  <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-10">
                    {filteredProducts.map(product => (
                      <ProductCard 
                        key={product.id} 
                        product={product} 
                        color="text-indigo-600"
                        onAddToCart={addToCart}
                        onQuickView={setSelectedProduct}
                      />
                    ))}
                  </div>
                ) : (
                  <div className="text-center py-24 opacity-50">
                     <AppIcon name="Search" size={64} className="mx-auto mb-4" />
                     <p className="text-xl font-bold">لم نجد منتجات بهذا الاسم</p>
                  </div>
                )}
             </div>
          </section>
        ) : (
          <div id="sections">
            {CATEGORIES.map((category, index) => (
              <div 
                key={category.id} 
                ref={el => sectionRefs.current[index] = el}
                className="scroll-mt-20 overflow-hidden"
              >
                <CategoryHero 
                  category={category} 
                  isActive={activeCategoryIndex === index} 
                />

                <div className={`py-32 ${category.bgLight}/40 relative`}>
                  <div className="max-w-7xl mx-auto px-6">
                    <div className="flex flex-col md:flex-row items-end justify-between mb-16 gap-6">
                      <div className="space-y-2">
                        <div className={`h-1 w-20 ${category.bgDark} rounded-full`}></div>
                        <h2 className="text-4xl md:text-5xl font-black text-slate-900">{category.title}</h2>
                        <p className="text-slate-500 text-lg">المنتجات الأكثر مبيعاً في هذا القسم</p>
                      </div>
                    </div>

                    <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-10">
                      {MOCK_PRODUCTS
                        .filter(p => p.category === category.id)
                        .map((product) => (
                          <ProductCard 
                            key={product.id} 
                            product={product} 
                            color={category.color}
                            onAddToCart={addToCart}
                            onQuickView={setSelectedProduct}
                          />
                        ))
                      }
                    </div>
                  </div>
                </div>
              </div>
            ))}
          </div>
        )}

        {/* Footer */}
        <footer className="bg-slate-950 text-white py-24 px-6 border-t border-white/5">
           <div className="max-w-7xl mx-auto text-center space-y-12">
              <div className="flex justify-center items-center gap-3">
                <AppIcon name="ShieldCheck" size={40} className="text-indigo-500" />
                <span className="text-4xl font-black text-white tracking-tighter">Lumière<span className="text-indigo-500">Derme</span></span>
              </div>
              <p className="text-slate-400 max-w-xl mx-auto">نحن نغير مفهوم العناية بالبشرة في الجزائر من خلال توفير المنتجات الأصلية والنصائح الطبية الموثوقة.</p>
              <div className="flex flex-wrap justify-center gap-8 text-slate-400 font-bold uppercase tracking-widest text-xs">
                 <span className="border border-white/10 px-4 py-2 rounded-full">توصيل لـ 58 ولاية</span>
                 <span className="border border-white/10 px-4 py-2 rounded-full">دفع عند الاستلام</span>
                 <span className="border border-white/10 px-4 py-2 rounded-full">منتجات أصلية 100%</span>
              </div>
              <div className="pt-8 text-slate-600 text-sm border-t border-white/5">© 2024 Lumière Derme International. Professional Skin Care Experience in Algeria.</div>
           </div>
        </footer>
      </main>

      {/* Floating Actions */}
      <div className="fixed bottom-6 right-6 z-[200] flex flex-col gap-4 items-end">
        <a 
          href="https://wa.me/213000000000" 
          target="_blank" 
          className="bg-green-500 text-white p-4 rounded-full shadow-2xl hover:scale-110 transition-all flex items-center gap-3 pr-6"
        >
          <AppIcon name="MessageCircle" />
