        {/* Center Logo */}
        <div 
          className="flex items-center gap-3 cursor-pointer absolute left-1/2 -translate-x-1/2" 
          onClick={() => window.scrollTo({top: 0, behavior: 'smooth'})}
        >
          <div className="bg-slate-950 p-2.5 rounded-xl text-white">
            <AppIcon name="ShieldCheck" size={28} />
