          >
            <div className="relative">
              <AppIcon name="ShoppingBag" size={18} />
              {cartCount > 0 && (
                <span className="absolute -top-2 -right-2 bg-indigo-500 text-white text-[9px] font-black w-4 h-4 rounded-full flex items-center justify-center ring-2 ring-slate-950">
