};

import React, { useState, useEffect, useRef } from 'react';
import { Navbar } from './components/Navbar';
import { CategoryHero } from './components/CategoryHero';
import { ProductCard } from './components/ProductCard';
import { CartSidebar } from './components/CartSidebar';
import { AIConsultant } from './components/AIConsultant';
import { ProductModal } from './components/ProductModal';
import { BrandMarquee } from './components/BrandMarquee';
import { CATEGORIES, MOCK_PRODUCTS } from './constants';
import { Product, CartItem } from './types';
import { AppIcon } from './components/Icons';

type View = 'store' | 'expertise';

function App() {
  const [view, setView] = useState<View>('store');
  const [cart, setCart] = useState<CartItem[]>([]);
  const [isCartOpen, setIsCartOpen] = useState(false);
  const [activeCategoryIndex, setActiveCategoryIndex] = useState(0);
  const [selectedProduct, setSelectedProduct] = useState<Product | null>(null);
  const [searchQuery, setSearchQuery] = useState('');
  const sectionRefs = useRef<(HTMLDivElement | null)[]>([]);
  const productsRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (view === 'store') {
      const handleScroll = () => {
        const scrollPos = window.scrollY + window.innerHeight / 2;
        sectionRefs.current.forEach((ref, index) => {
          if (ref && scrollPos >= ref.offsetTop && scrollPos < ref.offsetTop + ref.offsetHeight) {
            setActiveCategoryIndex(index);
          }
        });
      };
      window.addEventListener('scroll', handleScroll);
      return () => window.removeEventListener('scroll', handleScroll);
    }
  }, [view]);

  const handleNavigate = (target: string) => {
    if (target === 'about' || target === 'process') {
      setView('expertise');
      window.scrollTo({ top: 0, behavior: 'smooth' });
    } else if (target === 'sections') {
      setView('store');
      setTimeout(() => productsRef.current?.scrollIntoView({ behavior: 'smooth' }), 100);
    } else if (target === 'home') {
      setView('store');
      window.scrollTo({ top: 0, behavior: 'smooth' });
    }
  };

  const addToCart = (product: Product) => {
    setCart(prev => {
      const existing = prev.find(item => item.id === product.id);
      if (existing) {
        return prev.map(item => 
          item.id === product.id ? { ...item, quantity: item.quantity + 1 } : item
        );
      }
      return [...prev, { ...product, quantity: 1 }];
    });
    if (window.navigator.vibrate) window.navigator.vibrate(50);
    setIsCartOpen(true);
    setSelectedProduct(null);
  };

  const updateQuantity = (id: string, delta: number) => {
    setCart(prev => prev.map(item => 
      item.id === id ? { ...item, quantity: Math.max(1, item.quantity + delta) } : item
    ));
  };

  const removeFromCart = (id: string) => {
    setCart(prev => prev.filter(item => item.id !== id));
  };

  const filteredProducts = MOCK_PRODUCTS.filter(p => 
    p.name.toLowerCase().includes(searchQuery.toLowerCase()) || 
    p.description.toLowerCase().includes(searchQuery.toLowerCase())
  );

  const totalCartItems = cart.reduce((sum, item) => sum + item.quantity, 0);

  return (
    <div className="min-h-screen bg-white selection:bg-indigo-100 selection:text-indigo-900">
      <Navbar 
        onOpenCart={() => setIsCartOpen(true)} 
        cartCount={totalCartItems} 
        onSearch={setSearchQuery} 
        onNavigate={handleNavigate}
        currentView={view}
      />

      <main className="animate-in fade-in duration-700">
        {view === 'store' ? (
          <>
            {/* Store Hero */}
            <section className="h-[90vh] flex items-center justify-center text-center px-4 relative overflow-hidden bg-white">
              <div className="absolute inset-0 opacity-40">
                <div className="absolute inset-0 bg-gradient-to-b from-transparent via-white to-white z-10"></div>
                <img src="https://images.unsplash.com/photo-1556228720-195a672e8a03?auto=format&fit=crop&q=80&w=2000" className="w-full h-full object-cover grayscale" alt="Pure Skincare" />
              </div>

              <div className="relative z-20 max-w-5xl space-y-8 px-6">
                <h1 className="text-7xl md:text-[8rem] font-black text-slate-950 leading-[0.9] tracking-tighter">
                  الجمال برؤية <br/> <span className="text-indigo-600">طبية دقيقة</span>
                </h1>
                <p className="text-xl md:text-2xl text-slate-500 max-w-2xl mx-auto font-light leading-relaxed">
                  نحن لا نبيع المستحضرات، نحن نصمم رحلة تعافيك. استكشف مجموعاتنا المختارة بمعايير مخبرية صارمة.
                </p>
                <div className="flex flex-col md:flex-row gap-6 justify-center pt-8">
                  <button 
                    onClick={() => productsRef.current?.scrollIntoView({ behavior: 'smooth' })}
                    className="bg-slate-950 text-white px-12 py-6 rounded-2xl font-black text-lg hover:scale-105 active:scale-95 transition-all shadow-2xl"
                  >
                    تصفح المجموعات
                  </button>

                  {/* The Expert View Button */}
                  <button 
                    onClick={() => setView('expertise')}
                    className="group relative bg-white border-2 border-slate-100 text-slate-950 px-12 py-6 rounded-2xl font-black text-lg flex items-center gap-3 overflow-hidden transition-all hover:border-indigo-600"
                  >
                    <AppIcon name="ShieldCheck" size={20} className="text-indigo-600 group-hover:rotate-12 transition-transform" />
                    <span>فلسفتنا الطبية</span>
                    <div className="absolute inset-0 bg-indigo-50/0 group-hover:bg-indigo-50/50 transition-colors"></div>
                  </button>
                </div>
              </div>
            </section>

            <BrandMarquee />

            <div ref={productsRef}>
              {searchQuery ? (
                <section className="py-32 bg-white min-h-screen">
                  <div className="max-w-7xl mx-auto px-6">
                    <div className="mb-12">
                      <h2 className="text-3xl font-black text-slate-900">نتائج البحث: "{searchQuery}"</h2>
                    </div>
                    <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-10">
                      {filteredProducts.map(product => (
                        <ProductCard 
                          key={product.id} 
                          product={product} 
                          color="text-indigo-600"
                          onAddToCart={addToCart}
                          onQuickView={setSelectedProduct}
                        />
                      ))}
                    </div>
                  </div>
                </section>
              ) : (
                <div id="sections">
                  {CATEGORIES.map((category, index) => (
                    <div 
                      key={category.id} 
                      ref={el => sectionRefs.current[index] = el}
                      className="scroll-mt-20 overflow-hidden"
                    >
                      <CategoryHero 
                        category={category} 
                        isActive={activeCategoryIndex === index} 
                      />
                      <div className={`py-32 ${category.bgLight}/30`}>
                        <div className="max-w-7xl mx-auto px-6">
                          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-12">
                            {MOCK_PRODUCTS
                              .filter(p => p.category === category.id)
                              .map((product) => (
                                <ProductCard 
                                  key={product.id} 
                                  product={product} 
                                  color={category.color}
                                  onAddToCart={addToCart}
                                  onQuickView={setSelectedProduct}
                                />
                              ))
                            }
                          </div>
                        </div>
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </div>
          </>
        ) : (
          /* Expertise Page View */
          <div className="pt-24 animate-in slide-in-from-bottom-10 duration-700">
             {/* Header Section */}
             <section className="py-32 bg-slate-950 text-white text-center relative overflow-hidden">
                <div className="absolute inset-0 opacity-10">
                   <img src="https://images.unsplash.com/photo-1576086213369-97a306d36557?auto=format&fit=crop&q=80&w=2000" className="w-full h-full object-cover" alt="Lab" />
                </div>
                <div className="max-w-4xl mx-auto px-6 relative z-10 space-y-8">
                   <div className="w-20 h-20 bg-indigo-600 rounded-3xl flex items-center justify-center mx-auto mb-10 shadow-2xl shadow-indigo-600/40">
                      <AppIcon name="ShieldCheck" size={40} />
                   </div>
                   <h2 className="text-5xl md:text-7xl font-black tracking-tighter">المسؤولية العلمية لـ <span className="text-indigo-500">Lumière</span></h2>
                   <p className="text-xl text-slate-400 font-light leading-relaxed">
                      نحن لا نتبع الصيحات العابرة؛ نحن نلتزم بالنتائج المثبتة سريرياً. اكتشف المعايير الصارمة التي تجعلنا المرجع الأول للعناية الطبية في الجزائر.
                   </p>
                </div>
             </section>

             {/* Detailed Standards */}
             <section className="py-40 bg-white">
                <div className="max-w-7xl mx-auto px-6">
                   <div className="grid grid-cols-1 lg:grid-cols-2 gap-32 items-center mb-40">
                      <div className="space-y-12">
                         <div className="space-y-4">
                            <span className="text-indigo-600 font-black tracking-widest text-xs uppercase">The Selection Protocol</span>
                            <h3 className="text-5xl font-black text-slate-900 leading-tight">كيف نقرر ما هو صالح <span className="underline decoration-indigo-600 underline-offset-8">لبشرتكم</span>؟</h3>
                         </div>
                         <p className="text-xl text-slate-500 leading-relaxed font-light">
                            يمر كل منتج في Lumière Derme عبر بروتوكول فحص ثلاثي المراحل يتضمن مراجعة تركيبة المواد النشطة، بلد المنشأ، ومدى ملاءمة القوام للمناخ الجزائري.
                         </p>
