                                  </div>
                               </div>
                            ))}
                         </div>
                      </div>
                      <div className="relative">
                         <img src="https://images.unsplash.com/photo-1579162234444-f81f124cbb77?auto=format&fit=crop&q=80&w=800" className="rounded-[4rem] shadow-2xl" alt="Medical Standard" />
                         <div className="absolute -bottom-10 -left-10 bg-white p-10 rounded-[3rem] shadow-2xl border border-gray-50 max-w-xs">
