        </div>
        <div className="w-12 h-[1px] bg-indigo-600 animate-[grow_1.5s_ease-in-out_infinite]"></div>
        <style>{`
          @keyframes grow { 0% { width: 0; } 50% { width: 100px; } 100% { width: 0; } }
        `}</style>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-white selection:bg-indigo-50">
      <Navbar 
        onOpenCart={() => setIsCartOpen(true)} 
        cartCount={cart.reduce((s, i) => s + i.quantity, 0)} 
        onSearch={setSearchQuery} 
        onNavigate={handleNavigate}
        currentView={state}
      />

      <main className="view-transition">
        {state === 'store' ? (
          <div className="pt-24">
            {/* Minimalist Visual Hero */}
            <section className="relative h-[85vh] flex items-center justify-center overflow-hidden">
               <div className="absolute inset-0">
                  <img src="https://images.unsplash.com/photo-1620916566398-39f1143ab7be?auto=format&fit=crop&q=80&w=2000" className="w-full h-full object-cover scale-105" alt="Luxury Skincare" />
                  <div className="absolute inset-0 bg-white/40"></div>
               </div>

               <div className="relative z-10 text-center space-y-12 px-6">
                  <div className="space-y-4">
                    <span className="text-[10px] font-black uppercase tracking-[0.5em] text-indigo-600">L'excellence Dermatologique</span>
                    <h2 className="text-6xl md:text-[9rem] font-black text-slate-950 leading-none tracking-tighter">
                      نقاء العلم <br/> <span className="text-white drop-shadow-2xl">في كل قطرة</span>
                    </h2>
                  </div>

                  <div className="flex flex-col md:flex-row gap-6 justify-center">
                    <button 
                      onClick={() => productsRef.current?.scrollIntoView({ behavior: 'smooth' })}
                      className="bg-slate-950 text-white px-14 py-7 rounded-full font-black text-sm uppercase tracking-widest hover:bg-indigo-600 transition-all shadow-2xl"
                    >
                      اكتشف المجموعات
                    </button>
                    <button 
                      onClick={() => setState('expertise')}
                      className="bg-white/80 backdrop-blur-md border border-slate-200 text-slate-950 px-14 py-7 rounded-full font-black text-sm uppercase tracking-widest hover:border-indigo-600 transition-all"
                    >
                      فلسفتنا الطبية
                    </button>
                  </div>
               </div>
            </section>

            <BrandMarquee />

            {/* Visual Grid of Categories */}
            <div ref={productsRef} className="space-y-32 py-32">
              {CATEGORIES.map((category) => (
                <section key={category.id} className="max-w-7xl mx-auto px-6">
                  <div className="flex flex-col md:flex-row items-end justify-between mb-16 gap-8">
                    <div className="space-y-2">
                      <span className={`text-xs font-black uppercase tracking-[0.3em] ${category.color}`}>{category.subtitle}</span>
                      <h3 className="text-5xl font-black text-slate-950">{category.title}</h3>
                    </div>
                    <p className="text-slate-400 max-w-md text-lg font-light leading-relaxed">{category.description}</p>
                  </div>

                  <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-8">
                    {MOCK_PRODUCTS
                      .filter(p => p.category === category.id)
                      .map((product) => (
                        <ProductCard 
                          key={product.id} 
                          product={product} 
                          color={category.color}
                          onAddToCart={addToCart}
                          onQuickView={setSelectedProduct}
                        />
                      ))
                    }
                  </div>
                </section>
              ))}
            </div>
          </div>
        ) : (
          /* Expertise Page: The Professional Identity */
          <div className="pt-24 animate-in fade-in slide-in-from-bottom-5 duration-1000">
             <section className="py-40 px-6 max-w-5xl mx-auto text-center space-y-16">
                <div className="space-y-6">
                   <div className="w-px h-24 bg-indigo-600 mx-auto mb-10"></div>
                   <h2 className="text-xs font-black uppercase tracking-[0.6em] text-indigo-600">The Manifesto</h2>
