              <div className="bg-indigo-600 p-2 rounded-xl"><AppIcon name="Sparkles" size={16} /></div>
              <div className="flex flex-col">
                <span className="font-black text-sm tracking-tight">AI Assistant</span>
                <span className="text-[8px] font-bold uppercase tracking-widest text-slate-400">Powered by Gemini</span>
              </div>
            </div>
            <button onClick={() => setIsOpen(false)} className="hover:rotate-90 transition-transform"><AppIcon name="X" size={18} /></button>
          </div>

          <div ref={scrollRef} className="flex-grow p-6 overflow-y-auto hide-scrollbar space-y-6 bg-slate-50/50">
            {messages.map((m, i) => (
              <div key={i} className={`flex ${m.role === 'user' ? 'justify-start' : 'justify-end'}`}>
                <div className={`max-w-[85%] p-4 rounded-2xl text-xs leading-relaxed font-medium shadow-sm ${
                  m.role === 'user' ? 'bg-slate-950 text-white rounded-tr-none' : 'bg-white text-slate-700 rounded-tl-none border border-slate-100'
                }`}>
                  {m.text}
                </div>
              </div>
            ))}
            {isTyping && (
              <div className="flex gap-2 items-center text-[10px] text-indigo-600 font-black animate-pulse">
                <div className="w-1.5 h-1.5 bg-indigo-600 rounded-full"></div>
                المستشار يحلل طلبك...
              </div>
            )}
          </div>

          <div className="p-4 bg-white border-t border-slate-50 flex gap-2">
            <input 
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyDown={(e) => e.key === 'Enter' && handleSend()}
              placeholder="بماذا يمكنني مساعدتك؟"
