import { GoogleGenAI } from "@google/genai";

export const getAIProductInsight = async (productName: string, category: string) => {
  try {
    // إنشاء المثيل داخل الدالة لضمان قراءة المفتاح من env في كل طلب
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `بصفتك خبير تجميل طبي، قدم وصفاً قصيراً وجذاباً جداً لمنتج اسمه "${productName}" في قسم "${category}". ركز على الفوائد الطبية والجمالية بأسلوب فاخر.`,
      config: {
        maxOutputTokens: 150,
      }
    });
    return response.text;
  } catch (error) {
    console.error("AI Insight Error:", error);
    return null;
  }
};

import { useState, useRef, useEffect } from 'react';
import { GoogleGenAI, GenerateContentResponse } from "@google/genai";
import { AppIcon } from './Icons';

export const AIConsultant: React.FC = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [messages, setMessages] = useState<{role: 'user' | 'model', text: string}[]>([
    {role: 'model', text: 'مرحباً بك في Lumière Derme! أنا مستشارك الطبي الذكي، كيف يمكنني مساعدتك في اختيار الروتين المناسب لبشرتك اليوم؟'}
  ]);
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
  }, [messages, isTyping]);

  const handleSend = async () => {
    if (!input.trim()) return;
    const userMsg = input;
    setInput('');
    setMessages(prev => [...prev, {role: 'user', text: userMsg}]);
    setIsTyping(true);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const responseStream = await ai.models.generateContentStream({
        model: 'gemini-3-flash-preview',
        contents: userMsg,
        config: {
          systemInstruction: 'أنت خبير تجميل طبي في متجر Lumière Derme. وظيفتك تقديم نصائح طبية احترافية ومختصرة باللغة العربية. شجع المستخدم على العناية ببشرته واقترح أنواع المنتجات المتاحة في المتجر (واقي شمس، مرطبات، سيرومات).'
        }
      });

      let fullText = "";
      setMessages(prev => [...prev, {role: 'model', text: ""}]);

      for await (const chunk of responseStream) {
        const chunkText = (chunk as GenerateContentResponse).text;
        if (chunkText) {
          fullText += chunkText;
          setMessages(prev => {
            const newMessages = [...prev];
            newMessages[newMessages.length - 1].text = fullText;
            return newMessages;
          });
        }
      }
    } catch (error) {
      setMessages(prev => [...prev, {role: 'model', text: 'نعتذر، المستشار مشغول حالياً. يمكنك المحاولة بعد قليل.'}]);
    } finally {
      setIsTyping(false);
    }
  };

  return (
    <div className="fixed bottom-6 right-6 z-[250]">
      {isOpen ? (
        <div className="bg-white w-[350px] h-[550px] rounded-[2.5rem] shadow-2xl flex flex-col overflow-hidden border border-slate-100 animate-in slide-in-from-bottom-10 duration-500">
          <div className="bg-slate-950 p-6 text-white flex justify-between items-center">
            <div className="flex items-center gap-3">
              <div className="bg-indigo-600 p-2 rounded-xl"><AppIcon name="Sparkles" size={16} /></div>
              <div className="flex flex-col">
                <span className="font-black text-sm tracking-tight">AI Assistant</span>
                <span className="text-[8px] font-bold uppercase tracking-widest text-slate-400">Live Consultation</span>
              </div>
            </div>
            <button onClick={() => setIsOpen(false)} className="hover:rotate-90 transition-transform p-2"><AppIcon name="X" size={18} /></button>
          </div>

          <div ref={scrollRef} className="flex-grow p-6 overflow-y-auto hide-scrollbar space-y-6 bg-slate-50/50">
            {messages.map((m, i) => (
              <div key={i} className={`flex ${m.role === 'user' ? 'justify-start' : 'justify-end'}`}>
                <div className={`max-w-[90%] p-4 rounded-2xl text-xs leading-relaxed font-medium shadow-sm ${
                  m.role === 'user' ? 'bg-slate-950 text-white rounded-tr-none' : 'bg-white text-slate-700 rounded-tl-none border border-slate-100'
                }`}>
                  {m.text || (m.role === 'model' && '...')}
                </div>
              </div>
            ))}
            {isTyping && (
              <div className="flex gap-2 items-center text-[10px] text-indigo-600 font-black animate-pulse bg-indigo-50/50 p-2 rounded-lg w-fit">
                <div className="w-1 h-1 bg-indigo-600 rounded-full animate-bounce"></div>
                <div className="w-1 h-1 bg-indigo-600 rounded-full animate-bounce [animation-delay:0.2s]"></div>
                المستشار يكتب...
              </div>
            )}
          </div>

          <div className="p-4 bg-white border-t border-slate-50 flex gap-2">
            <input 
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyDown={(e) => e.key === 'Enter' && handleSend()}
              placeholder="اسأل عن روتين بشرتك..."
              className="flex-grow bg-slate-50 border-none rounded-2xl px-4 py-4 text-xs focus:ring-2 focus:ring-indigo-600 outline-none font-bold"
            />
            <button onClick={handleSend} className="bg-slate-950 text-white p-4 rounded-2xl hover:bg-indigo-600 transition-colors shadow-lg shadow-indigo-200">
              <AppIcon name="ArrowLeft" size={18} />
            </button>
          </div>
        </div>
      ) : (
        <button 
          onClick={() => setIsOpen(true)}
          className="bg-slate-950 text-white px-8 py-5 rounded-full shadow-2xl hover:scale-105 active:scale-95 transition-all flex items-center gap-4 border-4 border-white"
        >
          <div className="relative">
            <AppIcon name="MessageCircle" size={20} className="text-indigo-400" />
            <span className="absolute -top-1 -right-1 w-2.5 h-2.5 bg-emerald-500 rounded-full border-2 border-slate-950"></span>
          </div>
          <span className="font-black text-xs uppercase tracking-widest">مستشارك الخاص</span>
        </button>
      )}
    </div>
  );
};

